const fs = require('fs');
const path = require('path');

const data = $input.first().json.body || $input.first().json;
const variant = (data.cv_variant || 'A').toUpperCase();

const cvFile = variant === 'B' ? 'cv_variant_b.md' : 'cv_variant_a.md';
const cvPath = path.join(process.cwd(), 'cv', cvFile);
const tailorPromptPath = path.join(process.cwd(), 'prompts', 'cv_tailor.md');

let baseCv, tailorPrompt;
try {
  baseCv = fs.readFileSync(cvPath, 'utf-8');
  tailorPrompt = fs.readFileSync(tailorPromptPath, 'utf-8');
} catch (e) {
  throw new Error(`File read error: ${e.message}`);
}

const userMessage = `JOB DESCRIPTION:\n${data.description}\n\n---\n\nBASE CV:\n${baseCv}`;

return [{
  json: {
    ...data,
    baseCv,
    tailorPrompt,
    userMessage,
    cvVariant: variant
  }
}];

const fs = require('fs');
const path = require('path');

const response = $input.first().json;
const tailoredCv = response.content && response.content[0] && response.content[0].text;

if (!tailoredCv) throw new Error('Claude returned empty CV');

const prev = $('Select CV Variant').first().json;
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const filename = `tailored_cv_${prev.company}_${prev.job_title}_${ts}.md`
  .replace(/[^a-zA-Z0-9_.-]/g, '_');

const outputDir = path.join(process.cwd(), 'output');
if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, { recursive: true });

const filePath = path.join(outputDir, filename);
fs.writeFileSync(filePath, tailoredCv, 'utf-8');

return [{ json: { ...prev, tailoredCvPath: filePath, tailoredCvFilename: filename } }];

const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const clPromptPath = path.join(process.cwd(), 'prompts', 'cover_letter.md');
const clPrompt = fs.readFileSync(clPromptPath, 'utf-8');

const userMessage = `Company: ${data.company}\nJob Title: ${data.job_title}\nLocation: ${data.location}\n\nJob Description:\n${data.description}\n\nTop Matching Signals:\n${(data.top_matches || []).join('\n')}`;

return [{ json: { ...data, clPrompt, clUserMessage: userMessage } }];

const fs = require('fs');
const path = require('path');

const response = $input.first().json;
const clText = response.content && response.content[0] && response.content[0].text;

if (!clText) throw new Error('Claude returned empty cover letter');

const prev = $('Build CL Prompt').first().json;
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const filename = `cover_letter_${prev.company}_${prev.job_title}_${ts}.txt`
  .replace(/[^a-zA-Z0-9_.-]/g, '_');

const filePath = path.join(process.cwd(), 'output', filename);
fs.writeFileSync(filePath, clText, 'utf-8');

return [{ json: { ...prev, coverLetterPath: filePath, coverLetterFilename: filename, coverLetterSent: true } }];

const data = $input.first().json;
const platform = (data.source_platform || '').toLowerCase();

let targetWebhook;
if (['capgemini', 'accenture', 'jll', 'cbre', 'ey', 'tier1'].some(t => platform.includes(t))) {
  targetWebhook = 'apply-tier1';
} else if (['linkedin_eu', 'indeed_eu', 'wttj', 'eurojobs', 'glassdoor_eu'].some(t => platform.includes(t))) {
  targetWebhook = 'apply-abroad';
} else {
  targetWebhook = 'apply-india';
}

return [{ json: { ...data, targetWebhook } }];
